mapper.select:
select u.id as user_id, u.username as username, u.name as name, u.status as status, u.email as email, u.phone as phone, u.create_time as createTime from user u where 1=1
and ( u.name like concat('%',#{name},'%') or u.username like concat('%',#{name},'%') or exists ( select 1 from user_role ur inner join role r on ur.role_id = r.id where ur.user_id = u.id and r.name like concat('%',#{name},'%') ) )
and u.status = #{status}
